var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"……어디부터 잘못됐던 걸까?","JPN":"……どこから間違えていたのだろう。","ENG":"...Where did it all go wrong?","TWN":"……是從哪裡開始出錯的呢？"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"……왜 이런 결과가 나온 걸까.","JPN":"……どうしてこんな結果になったのだろう。","ENG":"...How did it come to this?","TWN":"……為什麼會是這樣的結果？"},"stage":{"bg":"ALPHA_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"대체 어째서……","JPN":"いったいどうして……","ENG":"Why...?","TWN":"為什麼……"},"stage":{"bg":"ALPHA_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"<color=#ffd34c>그야…… 당연…… 하잖아요?</color>","JPN":"<color=#ffd34c>それは……決まっている……じゃないですか。</color>","ENG":"<color=#ffd34c>It’s obvious... isn’t it?</color>","TWN":"<color=#ffd34c>這……不是……當然的嗎？</color>"},"stage":{"bg":"ALPHA_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"<color=#ffd34c>할아버님…… 께서.</color>","JPN":"<color=#ffd34c>お祖父様……が。</color>","ENG":"<color=#ffd34c>Because, Grandfather...</color>","TWN":"<color=#ffd34c>爺爺……</color>"},"stage":{"bg":"ALPHA_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"<color=#ffd34c>그렇게…… 말씀…… 하셨으니까……</color>","JPN":"<color=#ffd34c>そう……おっしゃい……ましたから……</color>","ENG":"<color=#ffd34c>used... to say...</color>","TWN":"<color=#ffd34c>是……這麼……說的……</color>"},"stage":{"bg":"ALPHA_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"<color=#ffd34c>할아버님께서는…….</color>","JPN":"<color=#ffd34c>お祖父様は……</color>","ENG":"<color=#ffd34c>Grandfather used to...</color>","TWN":"<color=#ffd34c>爺爺……</color>"},"stage":{"bg":"ALPHA_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"……씨!","JPN":"……様！","ENG":"–up!","TWN":"……姐！"},"stage":{"bg":"black","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"……아가씨!","JPN":"……お嬢様！","ENG":"...Miss Jia, wake up!","TWN":"……小姐！"},"stage":{"bg":"black","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨 괜찮으세요? 식은 땀이 많이 나세요.","JPN":"お嬢様、大丈夫ですか？　冷や汗がひどいです。","ENG":"Are you all right? You’re sweating all over.","TWN":"小姐，你還好嗎？你流了好多汗。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이진 언니…….","JPN":"ホノカさん……","ENG":"Jin...","TWN":"李珍姐……"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"제가 잠깐 잠들었었군요.","JPN":"私、うっかり寝てしまったのですね。","ENG":"...I must’ve fallen asleep.","TWN":"我剛不小心睡著了。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"죄송합니다, 아무래도 일정을 좀 무리해서 잡은 것 같군요.","JPN":"申し訳ございません、スケジュールに少し無理があったようですね。","ENG":"I’m sorry... It appears that the schedule was a little too ambitious.","TWN":"抱歉，都怪我把小姐的行程排得太滿了。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"곧 도착입니다. 내리실 준비를.","JPN":"まもなく到着です、降りる準備をいたしましょう。","ENG":"Get ready. We’ll be arriving soon.","TWN":"我們就快到了，請準備下飛機。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"subtitle","speaker":null,"text":{"KOREA":"18:59 ARC-KP1\\n알파트릭스 본사, 상공\\n<color=#ffd34c>사건 발생 5시간 전</color>","JPN":"18:59 ARC-KP1\\nアルファトリックス本社、上空\\n<color=#ffd34c>事件発生5時間前</color>","ENG":"18:59 ARC-KP1\\nAirspace over Alphatrix HQ\\n<color=#ffd34c>5 hours before Incident</color>","TWN":"18:59 ARC-KP1\\n阿爾法崔克斯總公司上空\\n<color=#ffd34c>事件發生前5小時</color>"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨, 정말 괜찮으세요?","JPN":"お嬢様、本当に大丈夫ですか？","ENG":"Are you sure you’re okay, Miss Jia?","TWN":"小姐，你真的沒事嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 괜찮아요. 약간 편두통이 있을 뿐이니까요.","JPN":"ええ、大丈夫です。少し頭痛がするだけですから。","ENG":"Yes, I’m fine. Just a little headache.","TWN":"嗯，我沒事，只是有點頭痛而已。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"힘드시면 지금이라도 돌아갈까요? 무리하면서까지 연회에 참석하실 필요는…….","JPN":"もしお疲れなら、今からでも戻りましょうか？\\n無理をしてまで宴会に参加する必要は……","ENG":"Do you want us to turn around? Attending the banquet is not a priority...","TWN":"不舒服的話，還是我們先回去吧？不需要勉強自己參加宴……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아뇨. 할아버님께서 가르쳐주셨거든요. 가족끼리는 사이 좋게 지내야 한다고.","JPN":"いいえ、お祖父様はこうおっしゃいました。家族は仲良くあるべきだって。","ENG":"No. Grandfather taught me that I should get along with family.","TWN":"不行，我爺爺有說，家人之間要相親相愛。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"오늘은 일 년에 한 번뿐인 혁신의 밤이잖아요? 다른 가족분들이 기다리고 계실 거예요.","JPN":"今日は年に一度の革新の夕べですから。\\n家族の皆さんがお待ちになっていると思います。","ENG":"Tonight is the annual The Night of Innovation. Everyone else is will be waiting for us.","TWN":"今天是一年一度的革新之夜，大家一定都在等我們。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그렇군요, 알겠습니다.","JPN":"そうですね、承知いたしました。","ENG":"I see. Understood.","TWN":"那好吧。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다른 맴버 분들은 모두 도착하셨나요?","JPN":"他のメンバーのみなさんは全員到着されていますか？","ENG":"Have the other members arrived already?","TWN":"其他人都到了嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"네. 아가씨께서 주무시고 계실 때, 초원 양에게 연락받았습니다.","JPN":"はい、お嬢様がお休みになっている間に、\\nナオさんから到着の連絡を受けました。","ENG":"Yes. While you were sleeping, Chowon reported in.","TWN":"都到了，剛剛小姐睡著的時候，我有接到初源的通知。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇군요.","JPN":"そうですか。","ENG":"I see.","TWN":"那就好。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아쉬워라……. 저도 멤버 분들이랑 같이 지하철이라는 걸 꼭 타 보고 싶었는데.","JPN":"残念だわ……私もメンバーのみなさんと一緒に、地下鉄というモノに乗ってみたかったのに。","ENG":"It’s a shame... I wanted to ride the thing called the \\"subway\\" with everyone.","TWN":"真可惜……好想跟大家一起搭搭看地鐵喔。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"돌아갈 때는 꼭 다 같이 타고 가요. 이진 언니.","JPN":"帰りは絶対にみんなで乗りましょう、ホノカさん。","ENG":"Let’s ride it back home with the others, Jin.","TWN":"李珍姐，我們回程的時候就一起搭地鐵吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……아쉽게도 그건 좀 어려울 것 같군요.","JPN":"……残念ですが、それはちょっと難しいかと。","ENG":"...I’m afraid that might be difficult.","TWN":"……很抱歉，可能沒辦法。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"연회가 끝나고 부회장님께서 따로 호출하셔서요.","JPN":"宴会の後は、副会長に呼び出されていますので。","ENG":"The Vice Chairman wants to see me after the banquet is over.","TWN":"宴會結束後，副會長另外有事找我。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아하, 이진 언니는 이노베이션에 오기 전에는 숙부님의 비서셨죠?","JPN":"残念ですね。そういえば、ホノカさんはイノベーションに来る前、叔父様の秘書をされていましたよね？","ENG":"That’s right! You were Uncle’s secretary before joining Innovation.","TWN":"哦～李珍姐之前是叔叔的秘書對吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……네. 이젠 아니지만요.","JPN":"はい。今はもう違いますが……","ENG":"Yes... But not anymore.","TWN":"……是的，但現在不是。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇구나. 오랫동안 못 보셨으니까 비서 시절 생각이 많이 나시겠네요.","JPN":"そうでしたね。叔父様とは久しぶりに会いますし、\\n色々と秘書時代のことを思い出すひと時になりそうですね。","ENG":"I see. Then I’m sure you were delighted to see him again.","TWN":"那你們這麼久不見，應該會想起很多以前的事吧～"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님께서 가르쳐 주셨죠. 오래된 인연일수록 소중히 여겨야만 한다고요.","JPN":"お祖父様に教わったのです。古くからの縁ほど、大切にすべきだと。","ENG":"Grandfather always taught me that the older the relationship, the more important it is to cherish it.","TWN":"我爺爺有說，認識得越久，越要好好珍惜這段關係。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저희는 신경 쓰지 말고, 숙부님과 천천히 이야기 나누고 오세요.","JPN":"私たちのことは気にせず、叔父様とゆっくりなさってくださいね。","ENG":"Don’t worry about us, and enjoy your time with Uncle.","TWN":"你不用擔心我們，就跟叔叔好好敘舊吧～"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"subtitle","speaker":null,"text":{"KOREA":"19:32 ARC-KP1\\n알파트릭스 본사, 파티 홀\\n<color=#ffd34c>사건 발생 약 4시간 전</color>","JPN":"19:32 ARC-KP1\\nアルファトリックス本社、パーティーホール\\n<color=#ffd34c>事件発生の約4時間前</color>","ENG":"19:32 ARC-KP1\\nAlphatrix HQ, Party Hall\\n<color=#ffd34c>Approximately 4 hours before Incident</color>","TWN":"19:32 ARC-KP1\\n阿爾法崔克斯總公司，派對大廳\\n<color=#ffd34c>事件發生前約4小時</color>"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"우, 우와……!","JPN":"わ、わあっ……！","ENG":"W-wow...!","TWN":"哇賽……！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"역시 알파트릭스 임직원들이 전부 모이는 회식 자리다워……! 클래스가 달라!","JPN":"アルファトリックスの全社員が集う懇親会場はやっぱり違うね……！\\n別次元だよ！","ENG":"So this is what a banquet with all of the Alphatrix employees looks like...! It’s on another level!","TWN":"真不愧是阿爾法崔克斯所有職員一起參與的聚餐……！等級完全不一樣！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"여기도 디저트……!","JPN":"こっちもデザート……！","ENG":"Look at these desserts...!","TWN":"這裡也有甜點……！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L25_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"저기도 디저트……!","JPN":"あっちもデザート……！","ENG":"There’s even more over there...!","TWN":"那裡也有甜點……！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L26_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"좋아! 아침부터 쫄쫄 굶은 보람이 있어!","JPN":"よし！　朝からお腹を空かせた甲斐があるな！","ENG":"Okay, then! It was worthwhile not to eat anything today!","TWN":"非常好！不枉費我從早上餓到現在！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"……어라?","JPN":"……あれ？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"가브리엘! 너 지금 뭐하는 거야?","JPN":"ガブリエル！　何してるの？","ENG":"Gabriel! What are you doing?","TWN":"加布里埃爾！你在幹嘛？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"보면 모르는가, 소녀여. 음식을 포장하는 중이다.","JPN":"見てわからないのか、少女よ。食べ物を調達しているのだ。","ENG":"Can’t you see, girl? I’m packing food.","TWN":"這位少女，你看不出來嗎？我在打包啊。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"내일과 모레, 그리고 글피의 일용할 양식을 위해서.","JPN":"明日と明後日、そして明々後日のためにな。","ENG":"It’s food that I’ll eat tomorrow, the day after, and the next!","TWN":"這些是我明天、後天和大後天要吃的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"아니, 바보야! 남들 다 보는데 부끄럽지도 않아?!","JPN":"バカ！　みんなが見てるのに恥ずかしくないわけ！？","ENG":"Hey! Don’t you feel embarrassed doing that with everyone here?!","TWN":"你傻啦！大家都在看，不覺得丟臉嗎？！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"훗. 어리석은 건 그대다.","JPN":"フッ、愚かなのは君だ。","ENG":"Pfft! You are the foolish ones.","TWN":"呵，傻的是你。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"그렇게 다람쥐 도토리 감추듯 양 볼 가득 욱여넣어도 인간의 위장엔 한계가 존재하지.","JPN":"そうやってリスみたいにぎゅうぎゅうほっぺに詰めたところで、\\n人間の胃袋には限度がある。","ENG":"Even if you try stuffing your face like a squirrel, the human stomach can only hold so much.","TWN":"就算我們可以像倉鼠一樣，把食物藏在兩頰裡，但是能藏的數量畢竟有限的！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"그래서는 행복감의 <color=#ffd34c>균형</color>을 맞출 수가 없어.","JPN":"そんなことでは、幸福感の<color=#ffd34c>バランス</color>がとれない。","ENG":"With that, the <color=#ffd34c>balance</color> of happiness can’t be met.","TWN":"這樣是無法達到幸福感的<color=#ffd34c>平衡</color>的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L38_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"균형의 문제가 아니라 매너의 문제겠지!","JPN":"バランスじゃなくてマナーの問題でしょ！","ENG":"It’s not about balance, it’s a matter of having manners!","TWN":"現在又不是在說平衡的事，是禮貌的問題！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"이런 곳에서 음식 싸가는 게 민폐라는 자각은 있는 거야?","JPN":"こんな場所で食べ物の持ち帰りだなんて、\\nマナー違反だってことはわかってるの？","ENG":"Don’t you know how rude it is to pack food from places like this?","TWN":"你這樣打包會影響到別人吃的權利啦！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"어차피 남으면 버릴 것 아닌가?","JPN":"どうせ余ったら捨てるんだろう？","ENG":"But it’s all going to be thrown away, no?","TWN":"吃剩的不也是丟掉嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"내 행실이 그렇게 마음에 안 들면 실력으로 막아 봐라, 소녀여.","JPN":"私の行動がそんなに気に食わないなら、実力で阻止するがいい。","ENG":"Girl, if you think my actions are that bad, then try to stop me.","TWN":"你對我的行為有意見的話，有本事就來阻止我啊，少女！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"큭……! 드디어 본색을 드러내는군, 괴인 싹쓰러가!","JPN":"くっ……！　ついに本性を現したわね、この大食い怪人！","ENG":"Grr...! So now you show your true intentions, you monster scum!","TWN":"可惡……！終於原形畢露了吧！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"가면 카운터를 본받은 자로서, 너의 악행은 용서할 수 없다!","JPN":"仮面カウンターに追随する者として、あなたの悪態は許せないわ！","ENG":"As I follow in the footsteps of the Masked Counter, your misdeeds cannot be forgiven!","TWN":"身為蒙面制裁者的代言人，我絕不能原諒你的惡行！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"흠. 기개는 훌륭하군.","JPN":"ふむ、気概は感じるな。","ENG":"Hmm. I admire your spirit.","TWN":"哼，氣勢是100分啦，"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"하지만…….","JPN":"だが……","ENG":"But...","TWN":"不過……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L50_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"하지만?","JPN":"だが？","ENG":"But?","TWN":"不過？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"TWN":"不過？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"앗?! 실장님!","JPN":"あっ！？　室長！","ENG":"Huh?! Chief?!","TWN":"不過？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"TWN":"欸？！室長！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"……어, 어느 틈에!?","JPN":"……い、いつの間に！？","ENG":"Uhh... Since when were you...?!","TWN":"……你什麼時候出現的？！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"지금 연회장 한복판에서 칼자루에 손을 가져다 댄 것 같은데……","JPN":"今、宴会場のど真ん中で刀の柄に手をかけたように見えましたが……","ENG":"I could’ve sworn I saw the two of you getting ready to fight in the middle of this banquet...","TWN":"現在是要在大庭廣眾之下亮刀嗎……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"제가 잘못 본 게 맞겠죠?","JPN":"私の見間違いですよね？","ENG":"But it’s all my imagination, right?","TWN":"應該是我眼花吧？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"그, 그건 피치 못할 사정으로…….","JPN":"こ、これはやむを得ず……","ENG":"Th-there’s been a misunderstanding...","TWN":"那個…我也是逼不得已……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"분명 신신당부했을 텐데요.","JPN":"あれほど念を押したはずです。","ENG":"I told you all to behave tonight, didn’t I?","TWN":"我不是交代過你們嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L14_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"오늘은 1년에 단 한 번, 알파트릭스 전 임직원이 모이는 혁신의 밤.","JPN":"今日は年に一度、アルファトリックスの全社員が集まる革新の夕べ。","ENG":"The Night of Innovation is the one day of the year that all employees of Alphatrix gather together.","TWN":"今天是阿爾法崔克斯全集團一年一度的革新之夜。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L15_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"부디 오늘만큼은 이노베이션의 이름에 먹칠하는 일이 없길 바란다고.","JPN":"どうか今日だけはイノベーションの名前に\\n泥を塗るようなことをしないようにと言ったはずですが。","ENG":"Please do your best not to make a mockery of Innovation tonight.","TWN":"今天絕對不能丟公司的臉！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L18_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"……무, 물론이죠! 실장님!","JPN":"……も、もちろんです！　室長！","ENG":"O-of course! Chief!","TWN":"……那…那當然囉！室長！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"저흰 그냥 서로한테 어울리는 디저트를 추천해주고 있었거든요!","JPN":"私たちはお互い好きそうなデザートを勧めていただけですから！","ENG":"We were actually recommending each other desserts!","TWN":"我們剛只是在推薦對方好吃的甜點啦！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"어라!? 이런 곳에 푸석푸석해 보이는 머핀이!?","JPN":"あれ！？　こんな所にパサパサなマフィンが！？","ENG":"Ooh! Look at that muffin that looks so dry!","TWN":"哇！？看起來好蓬鬆的瑪芬喔！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"입 벌려, 가브리엘! 머핀 들어간다!","JPN":"口を開けて、ガブリエル！　マフィンが行くよーっ！","ENG":"Open up, Gabriel! This one’s for you!","TWN":"加布里埃爾！嘴巴打開，瑪芬要進去囉！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"……으읍! 바로 그렇다. 실장.","JPN":"……んぐぐ！　そのとおりだ、室長。","ENG":"Mmph! That's right, Chief.","TWN":"……唔唔！就是這樣啦，室長！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"엇!? 때마침 여기 소녀를 닮은 곰보 빵이……!?","JPN":"あれぇ！？　ちょうどこんなところに、とってもカチカチなメロンパンが……！？","ENG":"Huh?! This streusel bread looks like you, girl!","TWN":"喔？！這麼巧！這裡有和少女你長得一樣的芝麻麵包欸……？！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"둘 다 당장 그만두지 못해!","JPN":"二人とも今すぐやめなさい！","ENG":"Enough, you two!","TWN":"你們兩個立刻給我住手！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"후훗, 오늘도 두 분은 사이가 좋으시네요. 다행이에요.","JPN":"フフッ、今日もお二人は仲良しですね。ほほえましいです。","ENG":"Ho ho. I see you two are having fun.","TWN":"呵呵，你們感情還是這麼好，真好～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"……김 비서. 저 사람들은 뭐죠?","JPN":"……秘書よ、あの者たちはいったい何ですか？","ENG":"Mr. Kim, who are they?","TWN":"……金秘書，那些人是誰？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"고져스해야 하는 자리에 누가 저런 버릇없는 꼬맹이들을 데려왔답니까?","JPN":"ゴージャスでなければならないこの会場に、\\n誰があんな躾のなっていない子どもたちを連れてきたのでしょう？","ENG":"What are ill-mannered children doing at a sophisticated event like this?","TWN":"這裡這麼有水準，是誰把沒水準的小鬼帶來的？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_NULL","text":{"KOREA":"귀국하신 지 얼마 안 되셔서 국내 사정은 잘 모르시는군요.","JPN":"帰国されたばかりで、まだご存じなかったのですね。","ENG":"Allow me to fill you in on the details of what happened while you were out of the country.","TWN":"因為您才剛回國沒多久而有所不知。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_NULL","text":{"KOREA":"그룹의 프로모션용으로 설립했던 태스크포스입니다. 내부에서 꽤 유명하죠.","JPN":"グループプロモーションの一環として設立されたタスクフォースカンパニーです。\\n内部ではかなり有名ですよ。","ENG":"They are part of the Group’s promotional Task Force. They are quite well-known within the company.","TWN":"他們是專門用來替集團打廣告的特遣勢力，在集團裡的名氣滿大的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"아아, 그 얼굴 모를 최대 주주께서 제안하셨다던 언터처블 프로모션 팀?","JPN":"ああ、あの匿名の筆頭株主が提案したという\\nアンタッチャブル・プロモーションチームのことですか？","ENG":"Aah... The promotional team that the unknown biggest shareholder had suggested?","TWN":"喔～你說那個神祕的大股東提議的不受管制行銷小組嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"무슨 짓을 해도 내부에서 아무 간섭 못 한다는 그……?","JPN":"何をしても、内部からは一切干渉できないという噂の……？","ENG":"So that’s the division that gets away with anything...?","TWN":"集團完全不能干涉他們的任何行動……？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_NULL","text":{"KOREA":"사실은 좀 다릅니다. 윗분들 방침은 간섭하지 않는 게 아니라, 방치하는 거죠.","JPN":"実情は若干異なります。上層部の方針は干渉しないのではなく、\\n放置することになっています。","ENG":"Not quite like that. The higher-ups' policy is to leave them alone rather than intervene.","TWN":"其實有點出入，上面的想法是放任他們自取滅亡，而不是不干涉。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_NULL","text":{"KOREA":"작전 중에 실패해서 객사하길 바라면서요.","JPN":"作戦中に失敗して勝手に死んでくれることを願いながら。","ENG":"They do hope that some will die during their operations.","TWN":"希望他們直接在作戰時因公殉職。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"……객사? 대체 그게 무슨 말이죠?","JPN":"……勝手に死ぬ？　それはどういう意味でしょう？","ENG":"...Die? What do you mean?","TWN":"……因公殉職？這什麼意思？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"다이브마다 코스트도 꽤 될 텐데, 실패하길 바란다고요?","JPN":"ダイブにかかるコストも相当なはずなのに、失敗を望んでいると？","ENG":"Each dive is costly, and yet they want them to fail?","TWN":"每次躍入要花那麼多錢，卻希望他們戰敗？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_NULL","text":{"KOREA":"……대표님도 신씨 일가의 사정은 한 번쯤 들어 보셨을 텐데요.","JPN":"……代表もヒメノ家の事情について、一度は耳に入れたことがあるかと。","ENG":"I’m sure you’ve heard the rumors of the Shin family, have you not?","TWN":"……您應該也聽說過沈氏家族的事。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_NULL","text":{"KOREA":"돌아가신 회장님이 애지중지하던 <color=#ffd34c>손녀</color>에 대한 이야기를요.","JPN":"亡くなった会長が溺愛していた<color=#ffd34c>孫娘</color>についてです。","ENG":"About the late President’s <color=#ffd34c>granddaughter</color> that he so treasured.","TWN":"就是過世的會長最疼愛的<color=#ffd34c>孫女</color>的事。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"뭐? 그럼 혹시 그……?","JPN":"えっ？　じゃあ、まさかあの……？","ENG":"What? Then what you’re saying is...?","TWN":"什麼？難道是……？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"여기 계셨군요, 한참 찾았어요. 초원 씨.","JPN":"こちらにいらしたのですね。ずいぶん探しましたよ、ナオさん。","ENG":"There you are. I’ve been looking all over for you, Ms. Chowon.","TWN":"初源，我找了你好久，原來你在這裡。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"같이 케이크 먹으러 가요. 다들 기다리고 계세요.","JPN":"一緒にケーキを食べに行きましょう。皆さんもナオさんのことを待っていますよ。","ENG":"Let’s go have some cake. Everyone’s waiting.","TWN":"一起去吃蛋糕吧，大家都在等你呢。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"아뇨, 리더. 저는 여기서 좀 쉬고 있겠습니다.","JPN":"いいえ、リーダー。私はここで少し休みます。","ENG":"No thank you, Leader. I’ll stay here and rest.","TWN":"不了，老大。我想在這裡休息一下。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"다들 저희 팀을 주목하고 계셔서 몸 둘 바를 모르던 참이었거든요.","JPN":"みんなが私たちのチームに注目していて、\\nどうすれば良いのかわからなくなっていたところです。","ENG":"All eyes are on our team, so I’m stumped on what to do.","TWN":"大家好像一直在討論我們的事，我覺得有點不自在。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……흐음. 그렇군요.","JPN":"……ふむ、そうなのですね。","ENG":"...Hmm. As you wish, then.","TWN":"……嗯嗯，原來是這樣。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그럼, 제가 같이 있어 드릴게요.","JPN":"でしたら、私もご一緒します。","ENG":"Then, I’ll stay here with you.","TWN":"那我一起在這裡陪你。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"네? 아뇨, 일부러 그러실 필요까진…….","JPN":"え？　いえ、そこまでして頂く必要は……","ENG":"Huh? N-no, you don’t need to...","TWN":"什麼？不用啦，你不需要這樣……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님께서 그러셨거든요. 항상 직원분들을 가족처럼 생각하는 사람이 되라고요.","JPN":"お祖父様はこうおっしゃいました。\\n常に社員の皆さんを家族のように気遣える人になりなさいって。","ENG":"Grandfather said that we need to treat our employees like family.","TWN":"我爺爺有說，要我把員工當家人一般看待。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"가족처럼……?","JPN":"家族のように……？","ENG":"Like... family?","TWN":"當家人……？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"이야, 직원은 가족처럼 생각하면서 정작 진짜 가족에게는 얼굴도 안 비추는구나?","JPN":"おいおい、社員は家族のように気遣うのに、\\n本当の家族のところには顔も出さないのか？","ENG":"Would you look at that. You treat your employees like family, but never come and show your face to your real ones?","TWN":"哎呀～說什麼把員工當作家人，結果對真正的家人卻是避而不見？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"그래도 한때는 사업 파트너였는데 좀 섭섭한데.","JPN":"これでも一時はビジネスパートナーだったのに、少し寂しいな。","ENG":"I mean, we were business partners once, right?","TWN":"虧我們還曾經是事業上的夥伴，真是傷我的心～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아, 안녕하세요! 재혁 오라버니!","JPN":"あ、ご無沙汰しています！　タツヤお兄様！","ENG":"H-hello! Jaehyuk!","TWN":"喔！大哥好！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"안 그래도 찾아뵈려 했는데, 죄송해요.","JPN":"ちょうどご挨拶に伺おうと思っていたところです。申し訳ありません。","ENG":"I’m sorry. I was just on my way to see you all.","TWN":"對不起，我正打算你找你的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"하하. 아냐, 아냐. 신경 쓰지 마. 지금이라도 봤으면 됐지, 뭘.","JPN":"ハハハ。いやいや、気にするな。こうやって会えたんだからいいんだよ。","ENG":"Hah hah. I got to see you now, so no worries.","TWN":"哈哈～沒事沒事，別緊張，現在見到面就好啦～呵～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"그보다 지아야. 괜찮은 비지니스가 있는데 어때? 한 번 들어 볼래?","JPN":"それよりユイ。良いビジネスチャンスがあるんだが、どうだ？　一度聞いてみないか？","ENG":"Anyway, Jia? I’ve got an interesting business proposition, if you care to listen?","TWN":"不過我想跟你談個生意，你要聽聽看嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"비지니스요?","JPN":"ビジネスチャンス？","ENG":"A business proposition?","TWN":"生意嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아하. 헤비암즈 건은 정말 유감이에요, 오라버니.","JPN":"そうでしたね！　ヘビーアームズの件は本当に残念でした、お兄様。","ENG":"Oh, I’m truly sorry for what happened at Heavyarms.","TWN":"喔～重武裝的事我也覺得很遺憾，大哥。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"혹시 지금이라도 제 도움이 필요하시다면…….","JPN":"もし今からでも私の力添えが必要でしたら……","ENG":"If you’re ever in need of my help...","TWN":"有需要我幫忙的話……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"빌어먹을……!! 다시는 내 앞에서 그 얘기 꺼내지 말라고 했을……!","JPN":"バカ野郎……！！　俺の前で二度とその話をするなと言ったはず……！","ENG":"Hey...!! I thought I told you to never bring that up ever ag...!!","TWN":"該死的……！不准再在我面前提起那件事……！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"아, 아아아악!","JPN":"う、うぎゃああっ！","ENG":"Aaargh!!","TWN":"啊啊啊啊！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"어린 시절을 불우하게 보내셔서 대화 예절을 배울 기회가 없으셨나 보네요.","JPN":"不遇な子ども時代を過ごされたせいで、\\n会話のマナーが身についていないようですね。","ENG":"It appears that you had a difficult childhood and did not have the opportunity to learn proper conversational etiquette.","TWN":"是小時候家裡沒大人，所以沒人教你什麼是禮貌嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"원하시면 지금 당장 성인용 예절 주입 코스를 마련해 드리죠.","JPN":"お望みでしたら、今すぐ大人向けのマナー叩き込みコースをご用意いたしましょう。","ENG":"If you want, I could give you a quick lesson on proper manners.","TWN":"還是需要我現在就教你，跟人家對話的基本禮儀？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"이, 이거 놔!! 너 내가 누군 줄 알아?!","JPN":"は、放せ！！　俺が誰だかわかってるのか！？","ENG":"L-let go of me! Do you even know who you’re dealing with, huh?!","TWN":"給我放開！！你知道我是誰嗎？！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"초원 씨, 재혁 오라버니를 놔주세요.","JPN":"ナオさん、タツヤお兄様を放してください。","ENG":"Chowon, please let go of Jaehyuk.","TWN":"初源，請你放開大哥。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"젠장, 빌어먹을 용병 나부랭이가!","JPN":"ちくしょう、クソ傭兵の分際で！","ENG":"You filthy Mercenary! How dare you!","TWN":"該死的，你一個小小的傭兵！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"지아 너, 직원 교육을 어떻게 한 거야? 저딴 짓을 하면 당장 잘라야지!","JPN":"ユイ、お前のところの社員教育はどうなってるんだ？\\nこんなことしたら即クビに決まってるだろ！","ENG":"Jia, your dog has gone mad! Fire her this instance!","TWN":"沈佳，你是怎麼教育員工的？她這樣對我，你還不炒她魷魚？！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"죄송해요, 오라버니. 제가 대신 사과드릴게요.","JPN":"ごめんなさい、お兄様。私が代わりにお詫びします。","ENG":"I apologize on her behalf, Jaehyuk.","TWN":"大哥，抱歉，我代替她向你賠不是。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그보다 하실 말씀이라는 게……?","JPN":"それより、先ほどのお話とは……？","ENG":"But what was it you were trying to say...?","TWN":"不過大哥，你剛說的生意是……？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 숙부님이 회장 권한대행에서 물러나신다고요?","JPN":"はい？　叔父様が会長代行から退くですって……？","ENG":"Huh? Uncle is stepping down as acting President?","TWN":"什麼？叔叔要退出會長代理職務嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"그래. 실적 부진 때문에 다음 이사회 때 부회장 대신 새로운 회장을 세우려나 봐.","JPN":"ああ。業績不振という理由で、次回の理事会で\\n副会長の代わりに新しい会長を立てるようだ。","ENG":"Yeah. Due to his poor performance, the next board of directors seems to be trying to appoint someone new.","TWN":"對啊，因為集團經營不善，所以下次開董事會時，好像就會推選出新的會長。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"우리같이 그 인간에게 밉보였던 사람들에게도 찬스가 왔다 이거지.","JPN":"彼に嫌われている我々にも、ついにチャンス到来ってことさ。","ENG":"That means it’s our chance to get back at him.","TWN":"這對我們這些被他討厭的人而言，是個大好機會！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"찬스요……?","JPN":"チャンス……ですか？","ENG":"Our chance...?","TWN":"大好機會嗎……？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"그래! 알파트릭스 그룹 전체를 손에 넣을 수 있는 찬스!","JPN":"ああ！　アルファトリックスグループ全体を手に入れるチャンスだ！","ENG":"Yeah! Our chance to seize control of the entire Alphatrix Group!","TWN":"是啊！可以把阿爾法崔克斯集團整碗捧走的大好機會！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그 이야기는 혹시 어디서 들으셨어요?","JPN":"その話はどこからお聞きになったのですか？","ENG":"Where did you hear this from?","TWN":"請問這件事是聽誰說的？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"그야 당연히 날 밀어 주는 사람이지. 그리고 그게 뭐가 중요해?","JPN":"それは当然俺の後援者からさ。といっても、そんなことはどうでもいいだろう？","ENG":"From one of my backers, of course. But that’s not what’s important right now.","TWN":"當然是支持我的人囉！聽誰說的很重要嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"어때, 지아야. 날 회장이 되게 도와 주는 건. 부회장 자리는 네게 줄 테니까.","JPN":"どうだ、ユイ。俺が会長になれるように手伝ってくれるなら、\\n副会長の席を君にあげよう。","ENG":"So, what do you think, Jia? If you help me become President, I’ll give the Vice Chairman position to you.","TWN":"小佳，你怎麼說？只要你幫我坐上會長的位置，我就讓你做副會長！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"지금처럼 계속 무시당하면서 살긴 싫잖아? 네 실력과 내 인망을 하나로 합치면…….","JPN":"このまま無視され続けるのはイヤだろ？\\n君の能力と俺の人望を合わせれば……","ENG":"Aren’t you tired of being ignored in the family? But with your skills and my network working as one...","TWN":"像現在這樣被瞧不起，你不覺得很憋屈嗎？以你的能力再加上我的人脈……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"쯧쯧. 오자마자 추한 꼴을 보는구나. 회사 일이 애들 장난도 아닐진데.","JPN":"やれやれ、到着早々こんな醜態を見せられるなんて。\\n会社は子どものおままごとじゃないのに。","ENG":"Tsk, tsk. Already scheming, are we? Remember, running a business isn’t child’s play.","TWN":"嘖嘖，瞧你這什麼樣子，公司的事又不是小孩子在辦家家酒。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"하긴, 집안 돌아가는 꼴이 딱하니 젊은 것들에게도 기대할 것 없겠지만.","JPN":"まあ、一家全体が機能不全みたいなものだから、若い世代も期待薄だわね……","ENG":"Well, looking at how the family’s been doing, I didn’t expect much from you youngsters, and you did not disappoint.","TWN":"不過也是啦，現在家道中落，對年輕一輩的也沒什麼好期待的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"뭐야, 이 꼰대 흉내 내는 꼬맹이는?","JPN":"なんだ、この偉そうにしてるガキは？","ENG":"Huh? Who does this little child think she is?!","TWN":"搞什麼，這個講話那麼老氣的小鬼是誰？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"꼰대라고? 내가?","JPN":"偉そう？　私が？","ENG":"Are you talking about me?","TWN":"你說我老氣？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"못 배워 먹은 게 자랑이구나. 아버지가 이 꼴을 보셨으면 당장 호적에서 파 버렸을 게다.","JPN":"礼儀知らずにもほどがあるわ。父がこのザマを見てたら、一族から即追放だったはずよ。","ENG":"You wear your ignorance like a badge of honor. Father would be rolling in his grave if he saw what you were doing.","TWN":"沒大沒小的，爸爸要是看到你這副德性，一定會立刻把你除籍！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"하……. 하다하다 이젠 별 미친 게 다…….","JPN":"はあ……こりゃ、気でも触れてんじゃないのか……？","ENG":"Ugh... I don’t have time to deal with this...","TWN":"什……這是哪來的瘋……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"야, 김 비서! 이 꼬마 부모들 당장 데려 와! 어떤 연놈들인지 얼굴 좀 보게!","JPN":"おい、このガキの親を呼べ！　どんな面をしてるのか、この眼で確かめてやる！","ENG":"Mr. Kim! Bring this child’s parents in front of me right now! I’ll show them who they’re messing with!","TWN":"金秘書！立刻把這小鬼的爸媽給我找來！我要問問他們是怎麼教小孩的！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_NULL","text":{"KOREA":"도, 도련님……. 그게…….","JPN":"ぼ、坊ちゃま……それが……","ENG":"S-sir... The thing is...","TWN":"少…少爺……那個……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"미안하다만 아버지는 진즉 돌아가셨느니라.","JPN":"悪いけど、父はとっくに亡くなっているわ。","ENG":"Sorry to tell you, but my father’s been dead for quite awhile now.","TWN":"不好意思喔，我爸早就死咧？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"그리고 내 어머니는 너희 일가 사람들이 푼돈 얼마 쥐어 줘서 바다 건너로 보내 버렸지.","JPN":"そして母は、あなたの一族が小銭を握らせて海の向こうに追放してしまったの。","ENG":"As for my mother, your family sent her overseas with barely enough to rub two nickels together.","TWN":"而我媽媽也被你們一家人趕到海的另一邊！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"추방이라니요?","JPN":"追放ですって？","ENG":"What do you mean by that?","TWN":"逐出家門嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"뭐? 그게 갑자기 뭔 헛소리야?","JPN":"はあ？　いきなり何の冗談だ？","ENG":"Huh? What’s she even talking about?","TWN":"蛤？你在胡說八道什麼？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"항렬로는 내가 네 녀석보다 위라는 게다.","JPN":"一族の中では私が君より上の立場ということよ。","ENG":"I’m saying that I outrank you in the family.","TWN":"按照輩分，我可是在你之上！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"집안 어르신에게는 존대를 써야지, 신재혁?","JPN":"序列がわかったのなら口を慎まなくっちゃね、タツヤ？","ENG":"Now, how about showing some respect to your elders, hmm? Shin Jaehyuk?","TWN":"對家裡的長輩要有禮貌，沈赫！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"집안 어르신……?","JPN":"序列……？","ENG":"Elders...?","TWN":"家裡的長輩……？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HEAVYARMSCEO_NPC_ALPHA_NULL","text":{"KOREA":"김 비서! 저 꼬마가 한 얘기는 다 뭐야!","JPN":"おい、あのガキはいったい何をほざいているんだ？","ENG":"Mr. Kim! What’s this kid talking about?!","TWN":"金秘書！那小鬼在說什麼我怎麼都聽不懂？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_NULL","text":{"KOREA":"그게……. 죄송하지만 사실입니다, 도련님. 생체 인증까지 마치셔서 저희로선 도저히…….","JPN":"それが……申しあげにくいのですが、事実です。\\n生体認証まで済ませているので、私たちとしてはどうすることも……","ENG":"I’m sorry to inform you, but it’s all true sir. Her biometrics were already verified, so there was nothing we could do...","TWN":"那個……很抱歉，她說的是事實沒錯。我們有確認過她的身分，確實……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"만나서 반갑구나, 지아야. 아버지에게 얘기 많이 들었느니라.","JPN":"会えて嬉しいわ、ユイちゃん。父から話は色々聞いているわよ。","ENG":"Nice to see you, Jia. I heard a lot about you from Father.","TWN":"小佳，你好啊，我常聽爸爸提起你呢～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"네가 그리도 영특하다지. 못난 것들 상대해 주느라 고생이 이만저만 아니었겠구나.","JPN":"君はとても聡明だとか。\\nこれまでバカな連中を相手にするのにさぞ大変だったでしょうね。","ENG":"He told me how brilliant you are. I’m sure you get headaches from dealing with these fools all day long.","TWN":"爸爸常誇你聰明，要面對這些沒用的傢伙，應該很辛苦吧？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"영특하다는 칭찬은 할아버님 말고는 들은 적이 없었는데…….","JPN":"聡明だと誉めてくださったのは、お祖父様だけでしたが……","ENG":"The only person to say I say brilliant was Grandfather...","TWN":"只有爺爺會稱讚我聰明……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"혹시 그 아버지라는 분이…… 저희 할아버님인가요?","JPN":"まさかそのお父様という方は……私のお祖父様なのでしょうか？","ENG":"Is your father... my Grandfather?","TWN":"請問你說的爸爸……就是我們的爺爺嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"옳지. 잘 알아 봤다.","JPN":"さすがお察しがよいこと。","ENG":"There you go. Good job putting the pieces together.","TWN":"正確，真聰明。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"기억해 두거라, 지아야. 내 이름은 <color=#ffd34c>세실리아</color>.","JPN":"憶えておきなさい、ユイちゃん。私の名前は<color=#ffd34c>セシリア</color>。","ENG":"Jia, keep in mind who I am. My name is <color=#ffd34c>Cecilia</color>.","TWN":"小佳，你要記好喔，我叫<color=#ffd34c>賽希莉亞</color>。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아버지가 돌아가시자마자 둘째 부인이란 이유로 억울하게 쫓겨난 캐서린의 딸이자…….","JPN":"父が他界してすぐ、側妻だったなんて理由で無念にも締め出されたキャサリンの娘であり……","ENG":"I am the daughter of Father’s second wife, Catherine, who was forced into exile when Father passed away.","TWN":"爸爸過世時，二房 凱瑟琳遭逐出家門，而我就是他們的女兒……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"장차, 알파트릭스 그룹을 씹어 삼킬 이름일 테니!","JPN":"この先、アルファトリックスグループを掌握する存在なのだ！","ENG":"Remember my name, for I will be the successor to the Alphatrix Group!","TWN":"我會將整個阿爾法崔克斯集團奪回來！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"}]`);export{e as default};